output_items = []

for item in _items:
    html = item["json"].get("data", "")

    for pair in [
        ["<script", "</script>"],
        ["<style", "</style>"],
        ["<noscript", "</noscript>"]
    ]:
        start_tag = pair[0]
        end_tag = pair[1]

        while start_tag in html.lower():
            lower_html = html.lower()
            start = lower_html.find(start_tag)
            end = lower_html.find(end_tag, start)

            if start == -1 or end == -1:
                break

            html = html[:start] + " " + html[end + len(end_tag):]

    text = ""
    inside_tag = False

    for char in html:
        if char == "<":
            inside_tag = True
            text = text + " "
        elif char == ">":
            inside_tag = False
            text = text + " "
        elif inside_tag == False:
            text = text + char

    replacements = {
        "&nbsp;": " ",
        "&amp;": "&",
        "&quot;": '"',
        "&#x27;": "'",
        "&#39;": "'",
        "&rsquo;": "'",
        "&lsquo;": "'",
        "&rdquo;": '"',
        "&ldquo;": '"'
    }

    for old in replacements:
        text = text.replace(old, replacements[old])

    text = " ".join(text.split())

    output_items.append({
        "json": {
            "original_article": text
        }
    })

return output_items
